import{_ as t,o,c as i,a3 as n}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"Focus Mode & Outline","description":"Use Focus Mode to minimize distractions and the Outline panel to navigate long notes by heading.","frontmatter":{"title":"Focus Mode & Outline","description":"Use Focus Mode to minimize distractions and the Outline panel to navigate long notes by heading.","keywords":"focus mode, outline, navigation, heading, distraction-free","category":"Editor"},"headers":[],"relativePath":"editor/focus-mode.md","filePath":"editor/focus-mode.md","lastUpdated":1784665499000}'),a={name:"editor/focus-mode.md"};function l(s,e,d,r,u,c){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="focus-mode-outline" tabindex="-1">Focus Mode &amp; Outline <a class="header-anchor" href="#focus-mode-outline" aria-label="Permalink to &quot;Focus Mode &amp; Outline&quot;">​</a></h1><h2 id="outline-panel" tabindex="-1">Outline Panel <a class="header-anchor" href="#outline-panel" aria-label="Permalink to &quot;Outline Panel&quot;">​</a></h2><p>The Outline panel shows a navigation tree of all headings in the current note. Use it to jump quickly between sections in long documents.</p><h3 id="open-the-outline" tabindex="-1">Open the Outline <a class="header-anchor" href="#open-the-outline" aria-label="Permalink to &quot;Open the Outline&quot;">​</a></h3><ul><li><strong>Menu:</strong> View → Show Outline</li><li><strong>Shortcut:</strong> <code>Ctrl + Alt + L</code></li></ul><h3 id="using-the-outline" tabindex="-1">Using the Outline <a class="header-anchor" href="#using-the-outline" aria-label="Permalink to &quot;Using the Outline&quot;">​</a></h3><ul><li>Click any heading in the Outline panel to scroll the editor to that section.</li><li>The Outline updates in real time as you write.</li><li>The active heading is highlighted based on the editor scroll position.</li><li>Works in Edit, Split, and Preview modes.</li></ul><div class="info custom-block"><p class="custom-block-title">Focus Mode Interaction</p><p>The Outline panel is <strong>automatically hidden</strong> when Focus Mode is active. Toggle Focus Mode off to use the Outline.</p></div><hr><h2 id="focus-mode" tabindex="-1">Focus Mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus Mode&quot;">​</a></h2><p>Focus Mode reduces visual distractions by hiding the Outline panel and reducing surrounding chrome.</p><h3 id="toggle-focus-mode" tabindex="-1">Toggle Focus Mode <a class="header-anchor" href="#toggle-focus-mode" aria-label="Permalink to &quot;Toggle Focus Mode&quot;">​</a></h3><ul><li><strong>Menu:</strong> View → Focus Mode</li><li><strong>Shortcut:</strong> <code>Ctrl + Alt + F</code></li></ul><h3 id="what-changes-in-focus-mode" tabindex="-1">What Changes in Focus Mode <a class="header-anchor" href="#what-changes-in-focus-mode" aria-label="Permalink to &quot;What Changes in Focus Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Element</th><th>State</th></tr></thead><tbody><tr><td>Outline panel</td><td>Hidden</td></tr><tr><td>Status bar padding</td><td>Reduced</td></tr><tr><td>Surrounding UI</td><td>Simplified</td></tr></tbody></table><p>Focus Mode is ideal for extended writing sessions where you want minimal context-switching.</p><h3 id="exit-focus-mode" tabindex="-1">Exit Focus Mode <a class="header-anchor" href="#exit-focus-mode" aria-label="Permalink to &quot;Exit Focus Mode&quot;">​</a></h3><p>Press <code>Ctrl + Alt + F</code> again or use <strong>View → Focus Mode</strong> to toggle off.</p><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Combining with Split Mode</p><p>For maximum productivity, combine Split mode (editor + preview) with the Outline panel open. You can read the rendered output on the right while using the outline for navigation on the left.</p></div><div class="tip custom-block"><p class="custom-block-title">Long Notes</p><p>If your note is long enough to need an outline, consider whether it should be split into separate notes linked with Markdown links. The graph view can help you see connections between notes.</p></div>',22)])])}const g=t(a,[["render",l]]);export{p as __pageData,g as default};
